// Created: 2026-03-06

/**
 * Session Summary - Stop Hook
 *
 * Runs at session end. Only fires when session had meaningful work (>=20 tool calls).
 * Builds a graph entity suggestion via additionalContext and nudges /ork:remember
 * for high-activity sessions (>50 tool calls).
 *
 * Graph-first replacement for memory-capture.ts — no local file writes.
 */

import type { HookInput, HookResult , HookContext} from '../types.js';
import { outputSilentSuccess, logHook, getProjectDir, getCachedBranch } from '../lib/common.js';
import { getTotalTools } from '../lib/metrics.js';

/**
 * Classify session outcome from last assistant message (CC 2.1.47)
 */
function classifySessionOutcome(msg: string): 'question' | 'summary' | 'code' | 'unknown' {
  const trimmed = msg.trimEnd();
  if (trimmed.endsWith('?')) return 'question';
  if (trimmed.includes('```')) return 'code';
  if (/\b(completed|summary|done|finished|implemented|fixed)\b/i.test(trimmed)) return 'summary';
  return 'unknown';
}

/**
 * Format today as YYYY-MM-DD without using Date methods that vary by locale.
 */
function todayISO(): string {
  return new Date().toISOString().slice(0, 10);
}

/**
 * Suggest a knowledge-graph entity capture at session end.
 * Only fires when session had meaningful work (>=20 tool calls).
 */
export function sessionSummary(input: HookInput, ctx?: HookContext): HookResult {
  (ctx?.log ?? logHook)('session-summary', 'Stop hook — checking session for graph capture');

  const totalTools = getTotalTools();

  if (totalTools < 20) {
    (ctx?.log ?? logHook)('session-summary', `Session had ${totalTools} tool calls (<20), skipping`);
    return outputSilentSuccess();
  }

  const projectDir = input.project_dir || (ctx?.projectDir ?? getProjectDir());
  const branch = ctx?.branch ?? getCachedBranch(projectDir);
  const date = todayISO();
  const entityName = `Session-${date}-${branch}`;

  const lastMsg = input.last_assistant_message ?? '';
  const outcome = lastMsg ? classifySessionOutcome(lastMsg) : 'unknown';

  const observation =
    `${totalTools} tool calls, outcome=${outcome}, branch=${branch}, project=${projectDir}`;

  const graphSuggestion = JSON.stringify({
    action: 'mcp__memory__create_entities',
    entities: [
      {
        name: entityName,
        entityType: 'session',
        observations: [observation],
      },
    ],
  });

  const lines: string[] = [
    `Session complete (${totalTools} tools, outcome=${outcome}).`,
    `Suggested graph capture: ${graphSuggestion}`,
  ];

  if (totalTools > 50) {
    lines.push('Consider running /ork:remember to save patterns from this session');
  }

  const additionalContext = lines.join('\n');

  (ctx?.log ?? logHook)('session-summary', `Built graph suggestion for entity "${entityName}"`);

  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: { additionalContext },
  };
}
